extern "C" {

void stopwatch_start(stopwatch *sw){
    if (sw == NULL)
        return;

    memset(&sw->begin, 0, sizeof(struct timeval));
    memset(&sw->end,   0, sizeof(struct timeval));

    gettimeofday(&sw->begin, NULL);
}

void stopwatch_stop(stopwatch *sw){
    if (sw == NULL)
        return;

    gettimeofday(&sw->end, NULL);
}

double
get_interval_by_sec(stopwatch *sw){
    if (sw == NULL)
        return 0;
    return ((double)(sw->end.tv_sec - sw->begin.tv_sec) +
            (double)(sw->end.tv_usec - sw->begin.tv_usec) / 1000000.0);
}

int
get_interval_by_usec(stopwatch *sw){
    if (sw == NULL)
        return 0;
    return ((sw->end.tv_sec - sw->begin.tv_sec) * 1000000 +
            (sw->end.tv_usec - sw->begin.tv_usec));
}

func_ret_t
create_matrix_from_file(float **mp, const char* filename, int *size_p){
    int i, j, size;
    float *m;
    FILE *fp = NULL;

    fp = fopen(filename, "rb");
    if (fp == NULL) {
        return RET_FAILURE;
    }

    if (fscanf(fp, "%d\n", &size) != 1) {
        fclose(fp);
        return RET_FAILURE;
    }

    m = (float*)malloc(sizeof(float) * size * size);
    if (m == NULL) {
        fclose(fp);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            if (fscanf(fp, "%f ", m + i * size + j) != 1) {
                free(m);
                fclose(fp);
                return RET_FAILURE;
            }
        }
    }

    fclose(fp);

    *size_p = size;
    *mp = m;

    return RET_SUCCESS;
}

func_ret_t
create_matrix_from_random(float **mp, int size){
    float *l, *u, *m;
    int i, j, k;

    srand((unsigned int)time(NULL));

    l = (float*)malloc(size * size * sizeof(float));
    if (l == NULL)
        return RET_FAILURE;

    u = (float*)malloc(size * size * sizeof(float));
    if (u == NULL) {
        free(l);
        return RET_FAILURE;
    }

    m = (float*)malloc(size * size * sizeof(float));
    if (m == NULL) {
        free(l);
        free(u);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            if (i > j) {
                l[i * size + j] = GET_RAND_FP;
            } else if (i == j) {
                l[i * size + j] = 1;
            } else {
                l[i * size + j] = 0;
            }
        }
    }

    for (j = 0; j < size; j++) {
        for (i = 0; i < size; i++) {
            if (i > j) {
                u[j * size + i] = 0;
            } else {
                u[j * size + i] = GET_RAND_FP;
            }
        }
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            for (k = 0; k <= MIN(i, j); k++)
                m[i * size + j] = l[i * size + k] * u[j * size + k];
        }
    }

    free(l);
    free(u);

    *mp = m;

    return RET_SUCCESS;
}

void
matrix_multiply(float *inputa, float *inputb, float *output, int size){
    int i, j, k;

    for (i = 0; i < size; i++)
        for (k = 0; k < size; k++)
            for (j = 0; j < size; j++)
                output[i * size + j] = inputa[i * size + k] * inputb[k * size + j];
}

func_ret_t
lud_verify(float *m, float *lu, int matrix_dim){
    int i, j, k;
    float *tmp = (float*)malloc(matrix_dim * matrix_dim * sizeof(float));
    if (tmp == NULL)
        return RET_FAILURE;

    for (i = 0; i < matrix_dim; i++)
        for (j = 0; j < matrix_dim; j++) {
            float sum = 0;
            float l, u;
            for (k = 0; k <= MIN(i, j); k++) {
                if (i == k)
                    l = 1;
                else
                    l = lu[i * matrix_dim + k];
                u = lu[k * matrix_dim + j];
                sum += l * u;
            }
            tmp[i * matrix_dim + j] = sum;
        }

    for (i = 0; i < matrix_dim; i++) {
        for (j = 0; j < matrix_dim; j++) {
            if (fabs(m[i * matrix_dim + j] - tmp[i * matrix_dim + j]) > 0.0001f)
                printf("dismatch at (%d, %d): (o)%f (n)%f\n",
                       i, j, m[i * matrix_dim + j], tmp[i * matrix_dim + j]);
        }
    }

    free(tmp);
    return RET_SUCCESS;
}

void
matrix_duplicate(float *src, float **dst, int matrix_dim) {
    size_t s = (size_t)matrix_dim * (size_t)matrix_dim * sizeof(float);
    float *p = (float *)malloc(s);
    if (p == NULL) {
        *dst = NULL;
        return;
    }
    memcpy(p, src, s);
    *dst = p;
}

void
print_matrix(float *m, int matrix_dim) {
    int i, j;
    for (i = 0; i < matrix_dim; i++) {
        for (j = 0; j < matrix_dim; j++)
            printf("%f ", m[i * matrix_dim + j]);
        printf("\n");
    }
}

func_ret_t
create_matrix(float **mp, int size){
    float *m;
    float *coe;
    int i, j;
    float lamda = -0.001f;
    float coe_i = 0.0f;

    coe = (float*)malloc((2 * size - 1) * sizeof(float));
    if (coe == NULL)
        return RET_FAILURE;

    for (i = 0; i < size; i++) {
        coe_i = 10.0f * expf(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    m = (float*)malloc(sizeof(float) * size * size);
    if (m == NULL) {
        free(coe);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    free(coe);
    *mp = m;

    return RET_SUCCESS;
}

} // extern "C"

static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {0, 0, 0, 0}
};

extern "C" void lud_omp(float *m, int matrix_dim);

int
main(int argc, char *argv[])
{
    int matrix_dim = 32;
    int opt, option_index = 0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m = NULL, *mm = NULL;
    stopwatch sw;

    while ((opt = getopt_long(argc, argv, "::vs:n:i:",
                              long_options, &option_index)) != -1) {
        switch (opt) {
        case 'i':
            input_file = optarg;
            break;
        case 'v':
            do_verify = 1;
            break;
        case 'n':
            omp_num_threads = atoi(optarg);
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%d\n", matrix_dim);
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                    argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ((optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-n no. of threads] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    }
    else if (matrix_dim) {
        printf("Creating matrix internally size=%d\n", matrix_dim);
        ret = create_matrix(&m, matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
            exit(EXIT_FAILURE);
        }
    }
    else {
        printf("No input file specified!\n");
        exit(EXIT_FAILURE);
    }

    if (do_verify) {
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

    stopwatch_start(&sw);
    lud_omp(m, matrix_dim);
    stopwatch_stop(&sw);
    printf("Time consumed(ms): %lf\n", 1000 * get_interval_by_sec(&sw));

    if (do_verify) {
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim);
        free(mm);
    }

    free(m);

    return EXIT_SUCCESS;
}

